    private static int[] generateNormalMode(int randomIndex, boolean is2xMode, int[] allCharacters) {
        int[] result = new int[allCharacters.length];
        if (is2xMode) {  //contain wild
            switch (randomIndex) {
                case 7:   //match H1
                    result = computeMatchH1(true, allCharacters);
                    break;
                case 8:   //match H2
                    result = computeMatchH2(true, allCharacters);
                    break;
                case 9:   //match H3
                    result = computeMatchH3(true, allCharacters);
                    break;
                case 10: //match H1H2
                    result = computeMatchH1H2(allCharacters);
                    break;
                case 11: //match H1H3
                    result = computeMatchH1H3(allCharacters);
                    break;
                case 12:  //match H2H3
                    result = computeMatchH2H3(allCharacters);
                    break;
                case 13:  //match H1H2H3
                    result = computeMatchH1H2H3(allCharacters);
                    break;
                default:
                    break;
            }
        } else {
            int weightIndex = RandomUtil.getRandomIndexFromArrayWithWeight(new int[]{9, 1});
            boolean isWild = weightIndex == 1;
            switch (randomIndex) {
                case 0:   //match H1
                    result = computeMatchH1(isWild, allCharacters);
                    break;
                case 1:   //match H2
                    result = computeMatchH2(isWild, allCharacters);
                    break;
                case 2:   //match H3
                    result = computeMatchH3(isWild, allCharacters);
                    break;
                case 3:
                    result = computeMatchH1H2(allCharacters);
                    break;
                case 4:
                    result = computeMatchH1H3(allCharacters);
                    break;
                case 5:
                    result = computeMatchH2H3(allCharacters);
                    break;
                case 6:
                    result = computeMatchH1H2H3(allCharacters);
                    break;
                default:
                    break;
            }

        }
        return result;
    }

